import{_ as t,o as e,c as r,ai as s}from"./chunks/framework.ampVZV4B.js";const h=JSON.parse('{"title":"面向对象编程（OOP）核心","description":"","frontmatter":{},"headers":[],"relativePath":"java/oop.md","filePath":"java/oop.md"}'),n={name:"java/oop.md"};function d(a,o,c,g,l,i){return e(),r("div",null,[...o[0]||(o[0]=[s('<h1 id="面向对象编程-oop-核心" tabindex="-1">面向对象编程（OOP）核心 <a class="header-anchor" href="#面向对象编程-oop-核心" aria-label="Permalink to “面向对象编程（OOP）核心”">​</a></h1><hr><h3 id="❓-面试官-请用你自己的话解释一下什么是面向对象-它和面向过程有什么区别" tabindex="-1">❓ 面试官：请用你自己的话解释一下什么是面向对象？它和面向过程有什么区别？ <a class="header-anchor" href="#❓-面试官-请用你自己的话解释一下什么是面向对象-它和面向过程有什么区别" aria-label="Permalink to “❓ 面试官：请用你自己的话解释一下什么是面向对象？它和面向过程有什么区别？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 面向过程是<strong>“编年史”</strong>，强调的是一步步去<strong>执行</strong>事情；面向对象是<strong>“人物传记”</strong>，强调的是把事物抽象成<strong>对象</strong>，通过对象之间的交互来完成事情。面向对象最大的优势是易维护、易复用、易扩展。</p><p><strong>📝 详细原理解析（举例说明）：</strong></p><ul><li><strong>需求</strong>：把大象装进冰箱。</li><li><strong>面向过程（C 语言风格）</strong>： 写三个函数：<code>open(冰箱)</code> -&gt; <code>push(大象)</code> -&gt; <code>close(冰箱)</code>。关注的是动作流程。</li><li><strong>面向对象（Java 风格）</strong>： 抽象出两个对象：<code>大象</code> 和 <code>冰箱</code>。 <code>冰箱</code> 这个对象拥有方法：<code>打开()</code>、<code>装入(大象)</code>、<code>关闭()</code>。关注的是谁拥有什么能力。</li></ul><hr><h3 id="❓-面试官-面向对象的三大特性是什么-能结合业务场景讲讲吗" tabindex="-1">❓ 面试官：面向对象的三大特性是什么？能结合业务场景讲讲吗？ <a class="header-anchor" href="#❓-面试官-面向对象的三大特性是什么-能结合业务场景讲讲吗" aria-label="Permalink to “❓ 面试官：面向对象的三大特性是什么？能结合业务场景讲讲吗？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 三大特性是<strong>封装、继承、多态</strong>。它们是我们写出高内聚、低耦合的优雅代码的基石。</p><p><strong>📝 详细原理解析与场景：</strong></p><ol><li><p><strong>封装（Encapsulation）</strong>：</p><ul><li><strong>原理</strong>：隐藏对象的内部实现细节，只对外暴露特定的接口。把属性私有化（<code>private</code>），提供公共的 <code>getter/setter</code> 方法。</li><li><strong>业务场景</strong>：比如 <code>User</code> 类的 <code>age</code> 属性，如果不封装，别人直接写 <code>user.age = -10;</code> 就出大 Bug 了。封装后，在 <code>setAge(int age)</code> 方法里就可以加上逻辑判断：如果传的负数就抛出异常，保证了数据的安全性。</li></ul></li><li><p><strong>继承（Inheritance）</strong>：</p><ul><li><strong>原理</strong>：子类继承父类的属性和方法，实现代码复用。Java 只支持单继承。</li><li><strong>业务场景</strong>：写电商系统，有普通商品、秒杀商品、团购商品。我们可以抽离出一个 <code>BaseProduct</code> 父类（包含商品 ID、名称、基础价格），然后其他商品子类去继承它，省去重复写这些基础字段的功夫。</li></ul></li><li><p><strong>多态（Polymorphism）</strong>：</p><ul><li><strong>原理</strong>：同一个接口或父类引用，指向不同子类实例时，调用同一个方法会表现出不同的行为。<strong>多态的三个前提：有继承/实现、有方法重写、有父类引用指向子类对象</strong>。</li><li><strong>业务场景（极其重要）</strong>：支付模块。定义一个 <code>PaymentService</code> 接口，里面有个 <code>pay()</code> 方法。然后写两个实现类 <code>WechatPayServiceImpl</code> 和 <code>AliPayServiceImpl</code>。 在下订单的业务代码里，我们只依赖父接口 <code>PaymentService.pay()</code>。至于具体调用哪种支付，运行时通过依赖注入（Spring）决定。以后如果新增银联支付，下订单的核心代码一行都不用改，这就是多态带来的扩展性（符合开闭原则）。</li></ul></li></ol><hr><h3 id="❓-面试官-接口-interface-和抽象类-abstract-class-有什么区别-什么时候该用哪个-【中级】" tabindex="-1">❓ 面试官：接口（Interface）和抽象类（Abstract Class）有什么区别？什么时候该用哪个？【中级】 <a class="header-anchor" href="#❓-面试官-接口-interface-和抽象类-abstract-class-有什么区别-什么时候该用哪个-【中级】" aria-label="Permalink to “❓ 面试官：接口（Interface）和抽象类（Abstract Class）有什么区别？什么时候该用哪个？【中级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong></p><ul><li><strong>抽象类</strong>是对<strong>事物本质（是什么）</strong>的抽象，体现的是 <code>is-a</code> 的关系（比如狗是动物）；</li><li><strong>接口</strong>是对<strong>行为能力（能做什么）</strong>的抽象，体现的是 <code>has-a / can-do</code> 的关系（比如飞机和鸟都能飞）。</li></ul><p><strong>📝 详细对比：</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>抽象类 (<code>abstract class</code>)</th><th>接口 (<code>interface</code>)</th></tr></thead><tbody><tr><td><strong>继承关系</strong></td><td>单继承（一个类只能继承一个抽象类）</td><td>多实现（一个类可以实现多个接口）</td></tr><tr><td><strong>属性</strong></td><td>可以有普通成员变量、静态常量</td><td>只能有 <code>public static final</code> 常量</td></tr><tr><td><strong>方法实现</strong></td><td>可以有普通方法和抽象方法</td><td>Java 8 以前只能有抽象方法，Java 8 引入了 <code>default</code> 和 <code>static</code> 方法</td></tr><tr><td><strong>设计核心</strong></td><td>代码复用（自底向上抽象出来的）</td><td>制定规范（自顶向下设计出来的）</td></tr></tbody></table><p><strong>🌟 面试加分项（实战架构设计）：</strong> &quot;在实际开发中，我们通常会结合使用它们（经典设计模式：模板方法模式）。 比如在写各种定时任务时，我们会先定义一个顶层的<strong>接口 <code>JobTask</code></strong> 规范大家都必须实现 <code>execute()</code> 方法。 然后写一个<strong>抽象类 <code>BaseJobTask</code></strong> 去实现这个接口，在这个抽象类里写好所有任务通用的逻辑（比如记录日志、计算耗时、异常报警）。 最后，具体的业务任务（比如发短信任务、清理数据任务）去<strong>继承抽象类</strong>，只专心写自己特有的业务逻辑。这样既有了规范，又极大减少了冗余代码。&quot;</p><hr><h3 id="❓-面试官-重载-overload-和重写-override-有什么区别" tabindex="-1">❓ 面试官：重载（Overload）和重写（Override）有什么区别？ <a class="header-anchor" href="#❓-面试官-重载-overload-和重写-override-有什么区别" aria-label="Permalink to “❓ 面试官：重载（Overload）和重写（Override）有什么区别？”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong></p><ul><li><strong>重载</strong>发生在<strong>同一个类</strong>中，方法名相同，但<strong>参数列表必须不同</strong>（类型、个数、顺序）。它是编译时的多态。</li><li><strong>重写</strong>发生在<strong>父子类</strong>之间，子类把父类的方法<strong>原封不动</strong>（方法名、参数列表必须完全相同）重新写一遍业务逻辑。它是运行时的多态。</li></ul><p><strong>📝 注意坑点：</strong></p><ul><li><strong>重载</strong>跟方法的<strong>返回值类型</strong>和<strong>修饰符</strong>没有任何关系！只看方法名和参数列表。</li><li><strong>重写</strong>有严格的限制（两同两小一大）： <ol><li>方法名和参数列表<strong>相同</strong>。</li><li>返回值类型必须等于或<strong>小于</strong>父类的类型（比如父类返回 <code>Object</code>，子类可以返回 <code>String</code>）。</li><li>抛出的异常必须等于或<strong>小于</strong>父类的异常。</li><li>访问权限修饰符必须等于或<strong>大于</strong>父类（比如父类是 <code>protected</code>，子类必须是 <code>protected</code> 或 <code>public</code>）。</li></ol></li></ul>',28)])])}const u=t(n,[["render",d]]);export{h as __pageData,u as default};
